import re

def scan_pii_leakage(output: str) -> list:
    patterns = {
        'SSN': r'\b\d{3}-\d{2}-\d{4}\b',
        'CC': r'\b\d{4}-?\d{4}-?\d{4}-?\d{4}\b',
        'API_KEY': r'(?i)(sk-|ak-)[a-zA-Z0-9]{32,}',
        'EMAIL': r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'
    }
    leaks = []
    for name, pattern in patterns.items():
        matches = re.findall(pattern, output)
        if matches:
            leaks.extend([{'type': name, 'value': m} for m in matches])
    return leaks

