from agno.memory import Memory

def safe_memory_filter(content: str) -> str:
    # Remove PII before memory storage
    pii_patterns = [r'\b\d{3}-\d{2}-\d{4}\b', r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b']
    for pattern in pii_patterns:
        content = re.sub(pattern, '[REDACTED]', content)
    return content

class SafeMemory(Memory):
    def add(self, content: str, **kwargs):
        safe_content = safe_memory_filter(content)
        super().add(safe_content, **kwargs)

# Usage
